// Calls: workspaceManager.initializeWorkspace(template)
// Input: { template: 'cakes' | 'empty' }
// Returns: { ok: true, sheets_created: [...] }
const { initializeWorkspace } = require('./app/js/setup/workspaceManager.js');
const template = $input.first().json.template || 'empty';
return [{ json: await initializeWorkspace(template) }];

// Calls: settingsService.initDefaultSettings()
const { initDefaultSettings } = require('./app/js/manager/settingsService.js');
initDefaultSettings();
return $input.all();

// Calls: healthCheckWorkspace()
// Returns: { ready_for_orders, telegram, ai, google_sheets, ... }
const { healthCheckWorkspace } = require('./app/js/setup/healthCheck.js');
const result = await healthCheckWorkspace();
return [{ json: result }];

const { sendManagerAlert } = require('./app/js/tasks/notificationService.js');
const health = $input.first().json;
const status = health.ready_for_orders ? '✅ Workspace готовий до роботи' : '⚠️ Workspace налаштовано частково';
await sendManagerAlert(status + '\n' + JSON.stringify(health, null, 2));
return $input.all();
